sys_security_acl.script:
//RJ TEMPLATE PERMISSIONS UPDATE
// This script was changed to allow the write script to work on a new record.
// the restriction has been placed on the template reference field.
// the template reference fitler field will filter records based on the user's permissions.
// when trying to add the script in this ACL, non-admin users could not see the data in the current on a new record.
// the run actions should all be pervented on the template for users trying to run a template without permissions.
// if a user is able to get to this form, by preventing the template selection, the user will be prevented from running a template.

var allow = false;
// STRY0113373 - this was actually a bug... updated to correct issue
if (current.isNewRecord()){
	allow = true;
} else {
	if(current.tasker_process){
		allow = new UserInfoScripts().userHasProcessRunRights(current.tasker_process);
	} else {
		// if this is a new record, let the validation happen on whether the user was able to get a template reference
		allow = true;
	}		
}

answer = allow;
